-- MissionModule.lua\n-- Módulo para gestionar misiones del jugador\n-- Se guarda en ReplicatedStorage\n\nlocal MissionModule = {}\n\n-- Variables locales\nlocal missions = {}\nlocal player_missions = {}\n\n-- Inicializa las misiones disponibles\nfunction MissionModule:InitializeMissions()\n\tmissions = {\n\t\t{\n\t\t\tid = 1,\n\t\t\ttitle = \"Ahorrador Principiante\",\n\t\t\tdescription = \"Ahorra 500 monedas en tu cuenta bancaria\",\n\t\t\tobjective = \"save_money\",\n\t\t\ttarget_value = 500,\n\t\t\treward = 100\n\t\t},\n\t\t{\n\t\t\tid = 2,\n\t\t\ttitle = \"Primer Empleo\",\n\t\t\tdescription = \"Consigue un trabajo para ganar dinero\",\n\t\t\tobjective = \"get_job\",\n\t\t\ttarget_value = 1,\n\t\t\treward = 50\n\t\t},\n\t\t{\n\t\t\tid = 3,\n\t\t\ttitle = \"Presupuesto Personal\",\n\t\t\tdescription = \"Crea tu primer presupuesto mensual\",\n\t\t\tobjective = \"create_budget\",\n\t\t\ttarget_value = 1,\n\t\t\treward = 75\n\t\t},\n\t\t{\n\t\t\tid = 4,\n\t\t\ttitle = \"Mi Primera Cuenta\",\n\t\t\tdescription = \"Abre una cuenta bancaria en el banco\",\n\t\t\tobjective = \"open_bank_account\",\n\t\t\ttarget_value = 1,\n\t\t\treward = 50\n\t\t},\n\t\t{\n\t\t\tid = 5,\n\t\t\ttitle = \"Consumo Responsable\",\n\t\t\tdescription = \"Compra solo productos necesarios\",\n\t\t\tobjective = \"responsible_purchase\",\n\t\t\ttarget_value = 5,\n\t\t\treward = 100\n\t\t},\n\t\t{\n\t\t\tid = 6,\n\t\t\ttitle = \"Inversionista Novato\",\n\t\t\tdescription = \"Realiza tu primera inversión\",\n\t\t\tobjective = \"invest\",\n\t\t\ttarget_value = 100,\n\t\t\treward = 150\n\t\t}\n\t}\n\t\n\tprint(\"[MissionModule] \" .. #missions .. \" misiones cargadas\")\nend\n\n-- Obtiene todas las misiones disponibles\nfunction MissionModule:GetAvailableMissions()\n\treturn missions\nend\n\n-- Obtiene una misión por ID\nfunction MissionModule:GetMissionById(mission_id)\n\tfor _, mission in ipairs(missions) do\n\t\tif mission.id == mission_id then\n\t\t\treturn mission\n\t\tend\n\tend\n\treturn nil\nend\n\n-- Activa una misión para un jugador\nfunction MissionModule:ActivateMission(player, mission_id)\n\tif not player_missions[player.UserId] then\n\t\tplayer_missions[player.UserId] = {}\n\tend\n\t\n\tlocal mission = self:GetMissionById(mission_id)\n\tif not mission then\n\t\tprint(\"Error: Misión \" .. mission_id .. \" no encontrada\")\n\t\treturn false\n\tend\n\t\n\tplayer_missions[player.UserId].current = mission\n\tplayer_missions[player.UserId].current.progress = 0\n\tplayer_missions[player.UserId].current.is_active = true\n\t\n\tprint(\"[MissionModule] Misión activada: \" .. mission.title .. \" para \" .. player.Name)\n\treturn true\nend\n\n-- Obtiene la misión actual de un jugador\nfunction MissionModule:GetCurrentMission(player)\n\tif not player_missions[player.UserId] then\n\t\treturn nil\n\tend\n\treturn player_missions[player.UserId].current\nend\n\n-- Actualiza el progreso de la misión actual\nfunction MissionModule:UpdateMissionProgress(player, progress)\n\tif not player_missions[player.UserId] or not player_missions[player.UserId].current then\n\t\treturn false\n\tend\n\t\n\tlocal mission = player_missions[player.UserId].current\n\tmission.progress = progress\n\t\n\tlocal progress_percent = (mission.progress / mission.target_value) * 100\n\tprint(\"[MissionModule] Progreso de '\" .. mission.title .. \"': \" .. string.format(\"%.1f\", progress_percent) .. \"%\")\n\t\n\tif mission.progress >= mission.target_value then\n\t\treturn self:CompleteMission(player)\n\tend\n\t\n\treturn false\nend\n\n-- Completa la misión actual\nfunction MissionModule:CompleteMission(player)\n\tif not player_missions[player.UserId] or not player_missions[player.UserId].current then\n\t\treturn false\n\tend\n\t\n\tlocal mission = player_missions[player.UserId].current\n\tprint(\"[MissionModule] ¡Misión completada! '\" .. mission.title .. \"' +\" .. mission.reward .. \" XP\")\n\t\n\tif not player_missions[player.UserId].completed then\n\t\tplayer_missions[player.UserId].completed = {}\n\tend\n\t\n\ttable.insert(player_missions[player.UserId].completed, mission)\n\tplayer_missions[player.UserId].current = nil\n\t\n\treturn true\nend\n\n-- Cancela la misión actual\nfunction MissionModule:CancelMission(player)\n\tif not player_missions[player.UserId] or not player_missions[player.UserId].current then\n\t\treturn false\n\tend\n\t\n\tlocal mission = player_missions[player.UserId].current\n\tprint(\"[MissionModule] Misión cancelada: \" .. mission.title)\n\tplayer_missions[player.UserId].current = nil\n\t\n\treturn true\nend\n\n-- Obtiene las misiones completadas\nfunction MissionModule:GetCompletedMissions(player)\n\tif not player_missions[player.UserId] then\n\t\treturn {}\n\tend\n\treturn player_missions[player.UserId].completed or {}\nend\n\nreturn MissionModule\n", "path": "scripts/MissionModule.lua